                    ?data_collection rdfs:label ?dc_label ;
                                     orkgp:DATA ?research_data ;
                                     orkgp:P1005 ?dc_method .

                    ?research_data orkgp:P7055 ?data_type .
                    ?data_type rdfs:label ?data_typeLabel .

                    ?dc_method orkgp:P94003 ?method_type .
                    ?method_type rdfs:label ?method_typeLabel .

                    BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
                    BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

                    FILTER(?dc_label != "no collection"^^xsd:string)
                    FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
                    FILTER(
                        ?data_typeLabel = "qualitative"^^xsd:string ||
                        ?data_typeLabel = "quantitative"^^xsd:string
                    )
                }
                GROUP BY ?decade ?data_type ?data_typeLabel
                         ?research_paradigm ?research_paradigmLabel
                         ?method_type ?method_typeLabel
            }
        }
        GROUP BY ?decade ?data_type ?data_typeLabel
    }

    {
        SELECT ?decade ?data_type ?data_typeLabel
               ?research_paradigm ?research_paradigmLabel
               ?method_type ?method_typeLabel
               (COUNT(DISTINCT ?paper) AS ?paper_count)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P57003 ?research_paradigm ;
                          orkgp:P56008 ?data_collection .

            ?venue rdfs:label ?venue_name .

            ?research_paradigm rdfs:label ?research_paradigmLabel .

            ?data_collection rdfs:label ?dc_label ;
                             orkgp:DATA ?research_data ;
                             orkgp:P1005 ?dc_method .

            ?research_data orkgp:P7055 ?data_type .
            ?data_type rdfs:label ?data_typeLabel .

            ?dc_method orkgp:P94003 ?method_type .
            ?method_type rdfs:label ?method_typeLabel .

            BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
            BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

            FILTER(?dc_label != "no collection"^^xsd:string)
            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
            FILTER(
                ?data_typeLabel = "qualitative"^^xsd:string ||
                ?data_typeLabel = "quantitative"^^xsd:string
            )
        }
        GROUP BY ?decade ?data_type ?data_typeLabel
                 ?research_paradigm ?research_paradigmLabel
                 ?method_type ?method_typeLabel
    }

    FILTER(?paper_count = ?max_paper_count)
}
ORDER BY ?decade ?data_typeLabel DESC(?paper_count) ?research_paradigmLabel ?method_typeLabel

SELECT ?inferential_statistics_group
       ?ml_algorithm
       ?ml_algorithmLabel
       ?metric_value
       (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    {
        SELECT DISTINCT ?paper ?inferential_statistics_group ?ml_algorithm ?ml_algorithmLabel ?metric_value
        WHERE {
            ?paper orkgp:P31 ?contribution .

            OPTIONAL { ?paper rdfs:label ?paperLabel . }

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P15124 ?data_analysis .

            ?venue rdfs:label ?venue_name .

            ?data_analysis rdfs:label ?da_label .

            ?data_analysis orkgp:P57016 ?machine_learning .

            ?machine_learning orkgp:P2001 ?ml_algorithm .

            OPTIONAL { ?ml_algorithm rdfs:label ?ml_algorithmLabel . }

            ?machine_learning orkgp:P2006 ?metric .

            {
                ?metric orkgp:P5073 ?recall .
                BIND("recall"^^xsd:string AS ?metric_value)
            }
            UNION
            {
                ?metric orkgp:P3004 ?precision .
                BIND("precision"^^xsd:string AS ?metric_value)
            }
            UNION
            {
                ?metric orkgp:P18048 ?accuracy .
                BIND("accuracy"^^xsd:string AS ?metric_value)
            }
            UNION
            {
                ?metric orkgp:P59137 ?f_score .
                BIND("f-score"^^xsd:string AS ?metric_value)
            }

            BIND(
                IF(
                    EXISTS {
                        ?data_analysis orkgp:P56043 ?inferential_statistics .
                    },
                    "with inferential statistics"^^xsd:string,
                    "without inferential statistics"^^xsd:string
                ) AS ?inferential_statistics_group
            )

            FILTER(?da_label != "no analysis"^^xsd:string)

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
    }
}

GROUP BY ?inferential_statistics_group ?ml_algorithm ?ml_algorithmLabel ?metric_value
ORDER BY ?inferential_statistics_group DESC(?paper_count) ?ml_algorithmLabel ?metric_value

SELECT ?year
       (SUM(?has_both_highlighted) AS ?papers_with_both_highlighted)
       (SUM(?has_both_highlighted_and_data_url_and_threats_mentioned) AS ?papers_with_both_highlighted_and_also_data_url_and_threats_mentioned)
WHERE {
    {
        SELECT ?paper ?year
               (MAX(?both_highlighted_flag) AS ?has_both_highlighted)
               (MAX(?all_conditions_flag) AS ?has_both_highlighted_and_data_url_and_threats_mentioned)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue .

            ?venue rdfs:label ?venue_name .

            ?contribution orkgp:P37330 ?research_question .
            ?research_question orkgp:P55039 ?rq_highlighted .

            ?contribution orkgp:P57004 ?research_question_answer .
            ?research_question_answer orkgp:P55039 ?rqa_highlighted .

            BIND(1 AS ?both_highlighted_flag)

            OPTIONAL {
                ?contribution orkgp:P56008 ?data_collection ;
                              orkgp:P39099 ?threats .

                ?data_collection rdfs:label ?dc_label ;
                                 orkgp:DATA ?research_data .

                ?research_data orkgp:url ?url .
                ?threats orkgp:P145000 ?mentioned .

                FILTER(?dc_label != "no collection"^^xsd:string)

                BIND(1 AS ?all_conditions_flag)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?year
    }
}
GROUP BY ?year
ORDER BY ?year

SELECT ?year ?reporting_case (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
    {
        SELECT ?paper ?year
               (MAX(?rq_flag) AS ?has_rq)
               (MAX(?rqa_flag) AS ?has_rqa)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue .

            ?venue rdfs:label ?venue_name .

            OPTIONAL {
                ?contribution orkgp:P37330 ?research_question .
                BIND(1 AS ?rq_flag)
            }

            OPTIONAL {
                ?contribution orkgp:P57004 ?research_question_answer .
                BIND(1 AS ?rqa_flag)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?year
    }

    BIND(
        IF(?has_rq = 1 && ?has_rqa = 1, "both reported"^^xsd:string,
            IF(?has_rq = 1 && (!BOUND(?has_rqa) || ?has_rqa != 1), "only research question reported"^^xsd:string,
                IF((!BOUND(?has_rq) || ?has_rq != 1) && ?has_rqa = 1, "only research question answer reported"^^xsd:string,
                    "neither reported"^^xsd:string
                )
            )
        ) AS ?reporting_case
    )
}
GROUP BY ?year ?reporting_case
ORDER BY ?year ?reporting_case

SELECT ?decade ?reporting_case (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
  {
    SELECT ?paper ?decade
           (MAX(?is_flag) AS ?has_is)
           (MAX(?ml_flag) AS ?has_ml)
    WHERE {
      ?paper orkgp:P31 ?contribution ;
             orkgp:P29 ?year .

      ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue ;
                    orkgp:P15124 ?data_analysis .

      ?venue rdfs:label ?venue_name .
      ?data_analysis rdfs:label ?da_label .

      BIND(xsd:integer(FLOOR(xsd:decimal(?year) / 10)) * 10 AS ?decade_start)
      BIND(CONCAT(STR(?decade_start), "s") AS ?decade)

      OPTIONAL {
        ?data_analysis orkgp:P56043 ?inferential_statistics .
        BIND(1 AS ?is_flag)
      }

      OPTIONAL {
        ?data_analysis orkgp:P57016 ?machine_learning .
        BIND(1 AS ?ml_flag)
      }

      FILTER(?da_label != "no analysis"^^xsd:string)
      FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
    }
    GROUP BY ?paper ?decade
  }

  BIND(
    IF(?has_is = 1 && ?has_ml = 1, "both"^^xsd:string,
      IF(?has_is = 1 && (!BOUND(?has_ml) || ?has_ml != 1), "inferential-statistics only"^^xsd:string,
        IF((!BOUND(?has_is) || ?has_is != 1) && ?has_ml = 1, "machine-learning only"^^xsd:string,
          "neither"^^xsd:string
        )
      )
    ) AS ?reporting_case
  )
}
GROUP BY ?decade ?reporting_case
ORDER BY ?decade ?reporting_case

SELECT ?coverage_class ?paper ?paperLabel ?validity_coverage_score
WHERE {
  {
    SELECT ?paper ?paperLabel (COUNT(DISTINCT ?category) AS ?validity_coverage_score)
    WHERE {
      ?paper orkgp:P31 ?contribution .
      OPTIONAL { ?paper rdfs:label ?paperLabel . }

      ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .

      ?venue rdfs:label ?venue_name .

      OPTIONAL {
        ?contribution orkgp:P39099 ?threats .

        {
          ?threats orkgp:P55037 ?v .
          BIND("construct validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P55035 ?v .
          BIND("internal validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P55034 ?v .
          BIND("external validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P55036 ?v .
          BIND("conclusion validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P59109 ?v .
          BIND("reliability"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P60006 ?v .
          BIND("generalizability"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P97002 ?v .
          BIND("repeatability"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P68005 ?v .
          BIND("content validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P97000 ?v .
          BIND("descriptive validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P97001 ?v .
          BIND("theoretical validity"^^xsd:string AS ?category)
        }
        UNION
        {
          ?threats orkgp:P145000 ?v .
          BIND("mentioned"^^xsd:string AS ?category)
        }
      }

      FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
    }
    GROUP BY ?paper ?paperLabel
  }

  BIND(
    IF(?validity_coverage_score = 0, "0"^^xsd:string,
      IF(?validity_coverage_score >= 1 && ?validity_coverage_score <= 2, "1–2"^^xsd:string,
        IF(?validity_coverage_score >= 3 && ?validity_coverage_score <= 4, "3–4"^^xsd:string,
          "5+"^^xsd:string
        )
      )
    ) AS ?coverage_class
  )
}
ORDER BY ?coverage_class DESC(?validity_coverage_score) ?paperLabel

SELECT ?year
       (COUNT(DISTINCT ?paper) AS ?papers_with_research_question)
       (SUM(?has_subquestion) AS ?papers_with_at_least_one_subquestion)
       ((COUNT(DISTINCT ?paper) - SUM(?has_subquestion)) AS ?papers_without_subquestion)
       ((100.0 * SUM(?has_subquestion)) / COUNT(DISTINCT ?paper) AS ?percentage_with_subquestion)
       ((100.0 * (COUNT(DISTINCT ?paper) - SUM(?has_subquestion))) / COUNT(DISTINCT ?paper) AS ?percentage_without_subquestion)
WHERE {
    {
        SELECT ?paper ?year (MAX(?subquestion_flag) AS ?has_subquestion)
        WHERE {
            ?paper orkgp:P31 ?contribution ;
                   orkgp:P29 ?year .

            ?contribution a orkgc:C27001 ;
                          orkgp:P135046 ?venue ;
                          orkgp:P37330 ?research_question .

            ?venue rdfs:label ?venue_name .

            OPTIONAL {
                ?research_question orkgp:P57000 ?subquestion .
                BIND(1 AS ?subquestion_flag)
            }

            FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
        }
        GROUP BY ?paper ?year
    }
}
GROUP BY ?year
ORDER BY ?year

SELECT ?venue ?venue_name ?reporting_case (COUNT(DISTINCT ?paper) AS ?paper_count)
WHERE {
  {
    SELECT ?paper ?venue ?venue_name
           (MAX(?hidden_flag) AS ?has_hidden)
           (MAX(?highlighted_flag) AS ?has_highlighted)
    WHERE {
      ?paper orkgp:P31 ?contribution .

      ?contribution a orkgc:C27001 ;
                    orkgp:P135046 ?venue .

      ?venue rdfs:label ?venue_name .

      OPTIONAL {
        ?contribution orkgp:P37330 ?rq_hidden .
        ?rq_hidden orkgp:P55038 ?hidden_value .
        BIND(1 AS ?hidden_flag)
      }

